sql:
SELECT COUNT(*)
FROM survival
WHERE vital_status = 'Alive';

SELECT patient_id, survival_status, vital_status
FROM survival
WHERE vital_status = 'Alive';

SELECT cancer_site_category
FROM cancer_sites
WHERE cancer_site_id = 1;

external_knowledge:
- "interacted with the profiles" refers to user actions logged in the access_logs table; 
- "those patients who are still living" means the vital status is 'Alive';
- "after more than a year" translates to more than 12 months of survival.

sql:
SELECT p.patient_id, a.access_outcome
FROM patients p
JOIN access_logs a ON p.patient_id = a.patient_id;
